165Ôćĺfunction formatContextPacket(packet: unknown): string {
166Ôćĺ  const p = packet as Record<string, unknown>;
167Ôćĺ  const lines: string[] = [];
168Ôćĺ
169Ôćĺ  lines.push("# Brain Knowledge Graph Context\n");
170Ôćĺ
171Ôćĺ  // Workspace & project
172Ôćĺ  const ws = p.workspace as { id: string; name: string } | undefined;
173Ôćĺ  const proj = p.project as { id: string; name: string; status: string; description?: string } | undefined;
174Ôćĺ  if (ws) lines.push(`Workspace: ${ws.name}`);
175Ôćĺ  if (proj) {
176Ôćĺ    lines.push(`Project: ${proj.name} (${proj.status})`);
177Ôćĺ    if (proj.description) lines.push(`Description: ${proj.description}`);
178Ôćĺ  }
179Ôćĺ  lines.push("");
180Ôćĺ
181Ôćĺ  // Task scope
182Ôćĺ  const taskScope = p.task_scope as Record<string, unknown> | undefined;
183Ôćĺ  if (taskScope) {
184Ôćĺ    const task = taskScope.task as { id: string; title: string; status: string; description?: string };
185Ôćĺ    lines.push(`## Current Task: ${task.title} [${task.status}]`);
186Ôćĺ    if (task.description) lines.push(task.description);
187Ôćĺ
188Ôćĺ    const subtasks = taskScope.subtasks as Array<{ id: string; title: string; status: string }>;
189Ôćĺ    if (subtasks?.length) {
190Ôćĺ      lines.push("\nSubtasks:");
191Ôćĺ      for (const s of subtasks) lines.push(`  - [${s.status}] ${s.title}`);
192Ôćĺ    }
193Ôćĺ
194Ôćĺ    const siblings = taskScope.sibling_tasks as Array<{ id: string; title: string; status: string }>;
195Ôćĺ    if (siblings?.length) {
196Ôćĺ      lines.push("\nSibling tasks:");
197Ôćĺ      for (const s of siblings) lines.push(`  - [${s.status}] ${s.title}`);
198Ôćĺ    }
199Ôćĺ    lines.push("");
200Ôćĺ  }
201Ôćĺ
202Ôćĺ  // Decisions
203Ôćĺ  const decisions = p.decisions as { confirmed: unknown[]; provisional: unknown[]; contested: unknown[] } | undefined;
204Ôćĺ  if (decisions) {
205Ôćĺ    if (decisions.contested.length > 0) {
206Ôćĺ      lines.push("## CONTESTED DECISIONS (conflicts ÔÇö do not proceed without human input)");
207Ôćĺ      for (const d of decisions.contested as Array<{ summary: string; rationale?: string }>) {
208Ôćĺ        lines.push(`  - ${d.summary}${d.rationale ? ` ÔÇö ${d.rationale}` : ""}`);
209Ôćĺ      }
210Ôćĺ      lines.push("");
211Ôćĺ    }
212Ôćĺ
213Ôćĺ    if (decisions.confirmed.length > 0) {
214Ôćĺ      lines.push("## Confirmed Decisions (follow these)");
215Ôćĺ      for (const d of decisions.confirmed as Array<{ summary: string }>) {
216Ôćĺ        lines.push(`  - ${d.summary}`);
217Ôćĺ      }
218Ôćĺ      lines.push("");
219Ôćĺ    }
220Ôćĺ
221Ôćĺ    if (decisions.provisional.length > 0) {
222Ôćĺ      lines.push("## Provisional Decisions (follow but flag for review)");
223Ôćĺ      for (const d of decisions.provisional as Array<{ summary: string }>) {
224Ôćĺ        lines.push(`  - ${d.summary}`);
225Ôćĺ      }
226Ôćĺ      lines.push("");
227Ôćĺ    }
228Ôćĺ  }
229Ôćĺ
230Ôćĺ  // Active tasks
231Ôćĺ  const tasks = p.active_tasks as Array<{ title: string; status: string; priority?: string }> | undefined;
232Ôćĺ  if (tasks?.length) {
233Ôćĺ    lines.push("## Active Tasks");
234Ôćĺ    for (const t of tasks) {
235Ôćĺ      lines.push(`  - [${t.status}]${t.priority ? ` (${t.priority})` : ""} ${t.title}`);
236Ôćĺ    }
237Ôćĺ    lines.push("");
238Ôćĺ  }
239Ôćĺ
240Ôćĺ  // Open questions
241Ôćĺ  const questions = p.open_questions as Array<{ text: string; status: string }> | undefined;
242Ôćĺ  if (questions?.length) {
243Ôćĺ    lines.push("## Open Questions");
244Ôćĺ    for (const q of questions) {
245Ôćĺ      lines.push(`  - [${q.status}] ${q.text}`);
246Ôćĺ    }
247Ôćĺ    lines.push("");
248Ôćĺ  }
249Ôćĺ
250Ôćĺ  // Recent changes
251Ôćĺ  const changes = p.recent_changes as Array<{ entity_type: string; entity_name: string; change_type: string; changed_at: string }> | undefined;
252Ôćĺ  if (changes?.length) {
253Ôćĺ    lines.push("## Recent Changes");
254Ôćĺ    for (const c of changes) {
255Ôćĺ      lines.push(`  - [${c.entity_type}] ${c.entity_name} ÔÇö ${c.change_type}`);
256Ôćĺ    }
257Ôćĺ    lines.push("");
258Ôćĺ  }
259Ôćĺ
260Ôćĺ  // Observations
261Ôćĺ  const observations = p.observations as Array<{ text: string; severity: string }> | undefined;
262Ôćĺ  if (observations?.length) {
263Ôćĺ    lines.push("## Observations");
264Ôćĺ    for (const o of observations) {
265Ôćĺ      lines.push(`  - [${o.severity}] ${o.text}`);
266Ôćĺ    }
267Ôćĺ    lines.push("");
268Ôćĺ  }
269Ôćĺ
270Ôćĺ  return lines.join("\n");
271Ôćĺ}
