 65Ôćĺ/** List active decisions for a project, optionally filtered by area/category */
 66Ôćĺexport async function listProjectDecisions(input: {
 67Ôćĺ  surreal: Surreal;
 68Ôćĺ  workspaceRecord: RecordId<"workspace", string>;
 69Ôćĺ  projectRecord: RecordId<"project", string>;
 70Ôćĺ  area?: string;
 71Ôćĺ}): Promise<{
 72Ôćĺ  confirmed: Array<{ id: string; summary: string; status: string; rationale?: string; decided_at?: string; category?: string }>;
 73Ôćĺ  provisional: Array<{ id: string; summary: string; status: string; rationale?: string; decided_at?: string; category?: string }>;
 74Ôćĺ  contested: Array<{ id: string; summary: string; status: string; rationale?: string; decided_at?: string; category?: string }>;
 75Ôćĺ}> {
 76Ôćĺ  const areaFilter = input.area
 77Ôćĺ    ? `AND category = $area`
 78Ôćĺ    : "";
 79Ôćĺ
 80Ôćĺ  const [rows] = await input.surreal
 81Ôćĺ    .query<[DecisionRow[]]>(
 82Ôćĺ      `SELECT id, summary, status, rationale, decided_at, category, priority, created_at
 83Ôćĺ       FROM decision
 84Ôćĺ       WHERE workspace = $workspace
 85Ôćĺ         AND id IN (SELECT VALUE \`in\` FROM belongs_to WHERE out = $project)
 86Ôćĺ         ${areaFilter}
 87Ôćĺ       ORDER BY created_at DESC LIMIT 50;`,
 88Ôćĺ      {
