 96Ôćĺ  type DecisionItem = { id: string; summary: string; status: string; rationale?: string; decided_at?: string; category?: string };
 97Ôćĺ  const confirmed: DecisionItem[] = [];
 98Ôćĺ  const provisional: DecisionItem[] = [];
 99Ôćĺ  const contested: DecisionItem[] = [];
100Ôćĺ
101Ôćĺ  for (const d of rows) {
102Ôćĺ    const item: DecisionItem = {
103Ôćĺ      id: toId(d.id),
104Ôćĺ      summary: d.summary,
105Ôćĺ      status: d.status,
106Ôćĺ      ...(d.rationale ? { rationale: d.rationale } : {}),
