119Ôćĺ/** Get task dependency tree (recursive) */
120Ôćĺexport async function getTaskDependencyTree(input: {
121Ôćĺ  surreal: Surreal;
122Ôćĺ  taskRecord: RecordId<"task", string>;
123Ôćĺ}): Promise<{
124Ôćĺ  task: { id: string; title: string; status: string };
125Ôćĺ  dependencies: Array<{ id: string; title: string; status: string; resolved: boolean }>;
126Ôćĺ  dependents: Array<{ id: string; title: string; status: string }>;
127Ôćĺ  subtasks: Array<{ id: string; title: string; status: string }>;
128Ôćĺ}> {
129Ôćĺ  const task = await input.surreal.select<TaskRow>(input.taskRecord);
130Ôćĺ  if (!task) throw new Error(`task not found: ${input.taskRecord.id}`);
131Ôćĺ
132Ôćĺ  const query = `
133Ôćĺ    -- Tasks this task depends on
134Ôćĺ    SELECT id, title, status
135Ôćĺ    FROM task
136Ôćĺ    WHERE id IN (SELECT VALUE out FROM depends_on WHERE \`in\` = $task);
137Ôćĺ
138Ôćĺ    -- Tasks that depend on this task
139Ôćĺ    SELECT id, title, status
140Ôćĺ    FROM task
141Ôćĺ    WHERE id IN (SELECT VALUE \`in\` FROM depends_on WHERE out = $task);
142Ôćĺ
143Ôćĺ    -- Subtasks
144Ôćĺ    SELECT id, title, status
145Ôćĺ    FROM task
146Ôćĺ    WHERE id IN (SELECT VALUE \`in\` FROM subtask_of WHERE out = $task)
147Ôćĺ    ORDER BY created_at ASC;
148Ôćĺ  `;
149Ôćĺ
150Ôćĺ  const results = await input.surreal
151Ôćĺ    .query<[DependencyRow[], DependencyRow[], SubtaskRow[]]>(query, { task: input.taskRecord })
