283Ôćĺ/** Create a subtask with semantic dedup */
284Ôćĺexport async function createSubtask(input: {
285Ôćĺ  surreal: Surreal;
286Ôćĺ  parentTaskRecord: RecordId<"task", string>;
287Ôćĺ  title: string;
288Ôćĺ  workspaceRecord: RecordId<"workspace", string>;
289Ôćĺ  category?: string;
290Ôćĺ  rationale?: string;
291Ôćĺ}): Promise<{ task_id: string; parent_task_id: string; already_existed: boolean }> {
292Ôćĺ  // Check for existing similar subtasks (semantic dedup by title)
293Ôćĺ  const normalizedTitle = input.title.toLowerCase().trim();
294Ôćĺ
295Ôćĺ  const [existingRows] = await input.surreal
296Ôćĺ    .query<[SubtaskRow[]]>(
297Ôćĺ      `SELECT id, title, status
298Ôćĺ       FROM task
299Ôćĺ       WHERE id IN (SELECT VALUE \`in\` FROM subtask_of WHERE out = $parent)
300Ôćĺ       ORDER BY created_at ASC;`,
301Ôćĺ      { parent: input.parentTaskRecord },
302Ôćĺ    )
303Ôćĺ    .collect<[SubtaskRow[]]>();
304Ôćĺ
305Ôćĺ  // Simple dedup: check if any existing subtask title is very similar
306Ôćĺ  for (const existing of existingRows) {
307Ôćĺ    const existingNormalized = existing.title.toLowerCase().trim();
308Ôćĺ    if (existingNormalized === normalizedTitle || levenshteinSimilarity(existingNormalized, normalizedTitle) > 0.85) {
309Ôćĺ      return {
310Ôćĺ        task_id: toId(existing.id),
311Ôćĺ        parent_task_id: toId(input.parentTaskRecord),
312Ôćĺ        already_existed: true,
313Ôćĺ      };
314Ôćĺ    }
315Ôćĺ  }
316Ôćĺ
317Ôćĺ  // Get parent task's category if not specified
318Ôćĺ  const parentTask = await input.surreal.select<TaskRow>(input.parentTaskRecord);
319Ôćĺ  if (!parentTask) throw new Error(`parent task not found: ${input.parentTaskRecord.id}`);
320Ôćĺ
321Ôćĺ  const now = new Date();
322Ôćĺ  const taskRecord = new RecordId("task", randomUUID());
323Ôćĺ
324Ôćĺ  await input.surreal.create(taskRecord).content({
325Ôćĺ    title: input.title,
326Ôćĺ    status: "todo",
327Ôćĺ    created_at: now,
328Ôćĺ    updated_at: now,
329Ôćĺ    workspace: input.workspaceRecord,
330Ôćĺ    ...(input.category ? { category: input.category } : parentTask.category ? { category: parentTask.category } : {}),
331Ôćĺ    ...(input.rationale ? { description: input.rationale } : {}),
332Ôćĺ  });
333Ôćĺ
334Ôćĺ  // Create subtask_of edge
335Ôćĺ  await input.surreal
336Ôćĺ    .relate(taskRecord, new RecordId("subtask_of", randomUUID()), input.parentTaskRecord, {
337Ôćĺ      added_at: now,
338Ôćĺ    })
339Ôćĺ    .output("after");
340Ôćĺ
341Ôćĺ  // Copy belongs_to edges from parent (inherit project/feature)
342Ôćĺ  const [parentBelongsTo] = await input.surreal
343Ôćĺ    .query<[Array<{ out: RecordId }>]>(
344Ôćĺ      "SELECT out FROM belongs_to WHERE `in` = $parent;",
345Ôćĺ      { parent: input.parentTaskRecord },
346Ôćĺ    )
347Ôćĺ    .collect<[Array<{ out: RecordId }>]>();
348Ôćĺ
349Ôćĺ  for (const edge of parentBelongsTo) {
350Ôćĺ    await input.surreal
351Ôćĺ      .relate(taskRecord, new RecordId("belongs_to", randomUUID()), edge.out, {
352Ôćĺ        added_at: now,
353Ôćĺ      })
354Ôćĺ      .output("after");
355Ôćĺ  }
356Ôćĺ
357Ôćĺ  return {
358Ôćĺ    task_id: toId(taskRecord),
359Ôćĺ    parent_task_id: toId(input.parentTaskRecord),
360Ôćĺ    already_existed: false,
361Ôćĺ  };
362Ôćĺ}
