371Ôćĺ  const now = new Date();
372Ôćĺ
373Ôćĺ  await input.surreal.update(input.taskRecord).merge({
374Ôćĺ    status: input.status,
375Ôćĺ    updated_at: now,
376Ôćĺ  });
377Ôćĺ
378Ôćĺ  if (input.notes) {
379Ôćĺ    // Append note to description_entries
380Ôćĺ    const task = await input.surreal.select<{ description_entries?: Array<{ text: string; created_at: Date }> }>(input.taskRecord);
381Ôćĺ    const entries = task?.description_entries ?? [];
382Ôćĺ    entries.push({ text: input.notes, created_at: now });
383Ôćĺ    await input.surreal.update(input.taskRecord).merge({ description_entries: entries });
384Ôćĺ  }
385Ôćĺ
386Ôćĺ  // Check if this task has a parent (subtask_of) and compute rollup
387Ôćĺ  const [parentRows] = await input.surreal
388Ôćĺ    .query<[Array<{ out: RecordId<"task", string> }>]>(
