587Ôćĺ  sha: string;
588Ôćĺ  message: string;
589Ôćĺ  filesChanged: Array<{ path: string; change_type: string; lines_added: number; lines_removed: number }>;
590Ôćĺ  author: string;
591Ôćĺ  taskUpdates?: Array<{ task_id: string; new_status: string }>;
592Ôćĺ  decisionsDetected?: Array<{ name: string; rationale: string }>;
