617Ôćĺ
618Ôćĺ  // Create provisional decisions if flagged
619Ôćĺ  let decisionsCreated = 0;
620Ôćĺ  if (input.decisionsDetected?.length) {
621Ôćĺ    for (const decision of input.decisionsDetected) {
