660Ôćĺ// ---------------------------------------------------------------------------
661Ôćĺ// Utility
662Ôćĺ// ---------------------------------------------------------------------------
663Ôćĺ
664Ôćĺfunction levenshteinSimilarity(a: string, b: string): number {
665Ôćĺ  if (a === b) return 1;
666Ôćĺ  const longer = a.length > b.length ? a : b;
667Ôćĺ  const shorter = a.length > b.length ? b : a;
668Ôćĺ  if (longer.length === 0) return 1;
669Ôćĺ
670Ôćĺ  const costs: number[] = [];
671Ôćĺ  for (let i = 0; i <= longer.length; i++) {
672Ôćĺ    let lastValue = i;
673Ôćĺ    for (let j = 0; j <= shorter.length; j++) {
674Ôćĺ      if (i === 0) {
675Ôćĺ        costs[j] = j;
676Ôćĺ      } else if (j > 0) {
677Ôćĺ        let newValue = costs[j - 1];
678Ôćĺ        if (longer.charAt(i - 1) !== shorter.charAt(j - 1)) {
679Ôćĺ          newValue = Math.min(Math.min(newValue, lastValue), costs[j]) + 1;
680Ôćĺ        }
681Ôćĺ        costs[j - 1] = lastValue;
682Ôćĺ        lastValue = newValue;
683Ôćĺ      }
684Ôćĺ    }
685Ôćĺ    if (i > 0) costs[shorter.length] = lastValue;
686Ôćĺ  }
687Ôćĺ
688Ôćĺ  return (longer.length - costs[shorter.length]) / longer.length;
689Ôćĺ}
