 89Ôćĺ/** Build a broad project context packet (all decisions, tasks, questions for a project) */
 90Ôćĺexport async function buildProjectContext(input: {
 91Ôćĺ  surreal: Surreal;
 92Ôćĺ  workspaceRecord: RecordId<"workspace", string>;
 93Ôćĺ  workspaceName: string;
 94Ôćĺ  projectRecord: RecordId<"project", string>;
 95Ôćĺ  taskId?: string;
 96Ôćĺ  since?: string;
 97Ôćĺ}): Promise<ContextPacket> {
 98Ôćĺ  const { surreal, workspaceRecord, workspaceName, projectRecord, taskId } = input;
 99Ôćĺ
100Ôćĺ  // Load project details
101Ôćĺ  const project = await surreal.select<ProjectRow>(projectRecord);
102Ôćĺ  if (!project) {
103Ôćĺ    throw new Error(`project not found: ${projectRecord.id}`);
104Ôćĺ  }
105Ôćĺ
106Ôćĺ  // Load project-scoped entities in parallel
107Ôćĺ  const projectEntitiesQuery = `
108Ôćĺ    LET $project_entity_ids = SELECT VALUE \`in\` FROM belongs_to WHERE out = $project;
109Ôćĺ
110Ôćĺ    SELECT id, summary, status, rationale, decided_at, category, priority
111Ôćĺ    FROM decision
112Ôćĺ    WHERE workspace = $workspace AND id IN $project_entity_ids
113Ôćĺ    ORDER BY created_at DESC LIMIT 50;
114Ôćĺ
115Ôćĺ    SELECT id, title, status, priority, category, description
116Ôćĺ    FROM task
117Ôćĺ    WHERE workspace = $workspace AND id IN $project_entity_ids
118Ôćĺ    ORDER BY created_at DESC LIMIT 50;
119Ôćĺ
120Ôćĺ    SELECT id, text, status, context, priority
121Ôćĺ    FROM question
122Ôćĺ    WHERE workspace = $workspace AND id IN $project_entity_ids
123Ôćĺ    ORDER BY created_at DESC LIMIT 30;
124Ôćĺ
125Ôćĺ    SELECT id, text, severity, status, category, observation_type
126Ôćĺ    FROM observation
127Ôćĺ    WHERE workspace = $workspace AND status IN ["open", "acknowledged"]
128Ôćĺ    ORDER BY created_at DESC LIMIT 20;
129Ôćĺ  `;
130Ôćĺ
131Ôćĺ  const results = await surreal
132Ôćĺ    .query<[null, DecisionRow[], TaskRow[], QuestionRow[], ObservationRow[]]>(projectEntitiesQuery, {
133Ôćĺ      project: projectRecord,
134Ôćĺ      workspace: workspaceRecord,
135Ôćĺ    })
136Ôćĺ    .collect<[null, DecisionRow[], TaskRow[], QuestionRow[], ObservationRow[]]>();
137Ôćĺ
138Ôćĺ  const [, decisionRows, taskRows, questionRows, observationRows] = results;
139Ôćĺ
140Ôćĺ  // Categorize decisions by status
141Ôćĺ  const confirmed: DecisionContext[] = [];
142Ôćĺ  const provisional: DecisionContext[] = [];
143Ôćĺ  const contested: DecisionContext[] = [];
144Ôćĺ
145Ôćĺ  for (const d of decisionRows) {
146Ôćĺ    const ctx: DecisionContext = {
147Ôćĺ      id: toId(d.id),
148Ôćĺ      summary: d.summary,
149Ôćĺ      status: d.status,
150Ôćĺ      ...(d.rationale ? { rationale: d.rationale } : {}),
151Ôćĺ      ...(d.decided_at ? { decided_at: toIso(d.decided_at) } : {}),
152Ôćĺ      ...(d.category ? { category: d.category } : {}),
153Ôćĺ      ...(d.priority ? { priority: d.priority } : {}),
154Ôćĺ    };
155Ôćĺ
156Ôćĺ    if (d.status === "contested") {
157Ôćĺ      contested.push(ctx);
158Ôćĺ    } else if (d.status === "provisional" || d.status === "inferred") {
159Ôćĺ      provisional.push(ctx);
160Ôćĺ    } else if (d.status === "confirmed") {
161Ôćĺ      confirmed.push(ctx);
162Ôćĺ    }
163Ôćĺ  }
164Ôćĺ
165Ôćĺ  // Map tasks
166Ôćĺ  const activeTasks: TaskContext[] = taskRows
167Ôćĺ    .filter((t) => t.status !== "done" && t.status !== "completed")
168Ôćĺ    .map((t) => ({
169Ôćĺ      id: toId(t.id),
170Ôćĺ      title: t.title,
171Ôćĺ      status: t.status,
172Ôćĺ      ...(t.priority ? { priority: t.priority } : {}),
173Ôćĺ      ...(t.category ? { category: t.category } : {}),
174Ôćĺ    }));
175Ôćĺ
176Ôćĺ  // Map questions
177Ôćĺ  const openQuestions: QuestionContext[] = questionRows
178Ôćĺ    .filter((q) => q.status !== "answered" && q.status !== "resolved")
179Ôćĺ    .map((q) => ({
180Ôćĺ      id: toId(q.id),
181Ôćĺ      text: q.text,
182Ôćĺ      status: q.status,
183Ôćĺ      ...(q.context ? { context: q.context } : {}),
184Ôćĺ      ...(q.priority ? { priority: q.priority } : {}),
185Ôćĺ    }));
186Ôćĺ
187Ôćĺ  // Map observations
188Ôćĺ  const observations: ObservationContext[] = observationRows.map((o) => ({
189Ôćĺ    id: toId(o.id),
190Ôćĺ    text: o.text,
191Ôćĺ    severity: o.severity,
192Ôćĺ    status: o.status,
193Ôćĺ    ...(o.category ? { category: o.category } : {}),
194Ôćĺ    ...(o.observation_type ? { observation_type: o.observation_type } : {}),
195Ôćĺ  }));
196Ôćĺ
197Ôćĺ  // Build recent changes if `since` provided
198Ôćĺ  const recentChanges: RecentChangeContext[] = input.since
199Ôćĺ    ? await loadRecentChanges(surreal, workspaceRecord, projectRecord, input.since)
200Ôćĺ    : [];
201Ôćĺ
202Ôćĺ  // Build task scope if taskId provided
203Ôćĺ  let taskScope: TaskScopeContext | undefined;
204Ôćĺ  if (taskId) {
205Ôćĺ    taskScope = await buildTaskScope(surreal, workspaceRecord, projectRecord, taskId);
206Ôćĺ  }
207Ôćĺ
208Ôćĺ  return {
209Ôćĺ    workspace: { id: workspaceRecord.id as string, name: workspaceName },
210Ôćĺ    project: {
211Ôćĺ      id: projectRecord.id as string,
212Ôćĺ      name: project.name,
213Ôćĺ      status: project.status,
214Ôćĺ      ...(project.description ? { description: project.description } : {}),
215Ôćĺ    },
216Ôćĺ    ...(taskScope ? { task_scope: taskScope } : {}),
217Ôćĺ    decisions: { confirmed, provisional, contested },
218Ôćĺ    active_tasks: activeTasks,
219Ôćĺ    open_questions: openQuestions,
220Ôćĺ    recent_changes: recentChanges,
221Ôćĺ    observations,
222Ôćĺ  };
223Ôćĺ}
