329Ôćĺ/** Load entities changed since a timestamp for the recent_changes field */
330Ôćĺasync function loadRecentChanges(
331Ôćĺ  surreal: Surreal,
332Ôćĺ  workspaceRecord: RecordId<"workspace", string>,
333Ôćĺ  projectRecord: RecordId<"project", string>,
334Ôćĺ  since: string,
335Ôćĺ): Promise<RecentChangeContext[]> {
336Ôćĺ  const sinceDate = new Date(since);
337Ôćĺ
338Ôćĺ  const query = `
339Ôćĺ    LET $project_entity_ids = SELECT VALUE \`in\` FROM belongs_to WHERE out = $project;
340Ôćĺ
341Ôćĺ    LET $recent_decisions = SELECT "decision" AS entity_type, summary AS entity_name, status AS change_type, updated_at AS changed_at
342Ôćĺ    FROM decision
343Ôćĺ    WHERE workspace = $workspace AND id IN $project_entity_ids AND updated_at > $since
344Ôćĺ    ORDER BY updated_at DESC LIMIT 20;
345Ôćĺ
346Ôćĺ    LET $recent_tasks = SELECT "task" AS entity_type, title AS entity_name, status AS change_type, updated_at AS changed_at
347Ôćĺ    FROM task
348Ôćĺ    WHERE workspace = $workspace AND id IN $project_entity_ids AND updated_at > $since
349Ôćĺ    ORDER BY updated_at DESC LIMIT 20;
350Ôćĺ
351Ôćĺ    LET $recent_questions = SELECT "question" AS entity_type, text AS entity_name, status AS change_type, updated_at AS changed_at
352Ôćĺ    FROM question
353Ôćĺ    WHERE workspace = $workspace AND id IN $project_entity_ids AND updated_at > $since
354Ôćĺ    ORDER BY updated_at DESC LIMIT 20;
355Ôćĺ
356Ôćĺ    RETURN array::flatten([$recent_decisions, $recent_tasks, $recent_questions]);
357Ôćĺ  `;
358Ôćĺ
359Ôćĺ  const results = await surreal
360Ôćĺ    .query<[null, null, null, null, RecentChangeRow[]]>(query, {
361Ôćĺ      project: projectRecord,
362Ôćĺ      workspace: workspaceRecord,
363Ôćĺ      since: sinceDate,
364Ôćĺ    })
365Ôćĺ    .collect<[null, null, null, null, RecentChangeRow[]]>();
366Ôćĺ
367Ôćĺ  const rows = results[4] ?? [];
368Ôćĺ
369Ôćĺ  return rows.map((r) => ({
370Ôćĺ    entity_type: r.entity_type,
371Ôćĺ    entity_name: r.entity_name,
372Ôćĺ    change_type: r.change_type,
373Ôćĺ    changed_at: toIso(r.changed_at),
374Ôćĺ  }));
375Ôćĺ}
376Ôćĺ
377Ôćĺtype RecentChangeRow = {
