 73Ôćĺ  provisional: Array<{ id: string; summary: string; status: string; rationale?: string; decided_at?: string; category?: string }>;
 74Ôćĺ  contested: Array<{ id: string; summary: string; status: string; rationale?: string; decided_at?: string; category?: string }>;
 75Ôćĺ}> {
 76Ôćĺ  const areaFilter = input.area
 77Ôćĺ    ? `AND category = $area`
 78Ôćĺ    : "";
