 82Ôćĺ      `SELECT id, summary, status, rationale, decided_at, category, priority, created_at
 83Ôćĺ       FROM decision
 84Ôćĺ       WHERE workspace = $workspace
 85Ôćĺ         AND id IN (SELECT VALUE \`in\` FROM belongs_to WHERE out = $project)
 86Ôćĺ         ${areaFilter}
 87Ôćĺ       ORDER BY created_at DESC LIMIT 50;`,
 88Ôćĺ      {
 89Ôćĺ        workspace: input.workspaceRecord,
 90Ôćĺ        project: input.projectRecord,
 91Ôćĺ        ...(input.area ? { area: input.area } : {}),
 92Ôćĺ      },
 93Ôćĺ    )
 94Ôćĺ    .collect<[DecisionRow[]]>();
 95Ôćĺ
 96Ôćĺ  type DecisionItem = { id: string; summary: string; status: string; rationale?: string; decided_at?: string; category?: string };
 97Ôćĺ  const confirmed: DecisionItem[] = [];
 98Ôćĺ  const provisional: DecisionItem[] = [];
 99Ôćĺ  const contested: DecisionItem[] = [];
100Ôćĺ
101Ôćĺ  for (const d of rows) {
102Ôćĺ    const item: DecisionItem = {
