169Ôćĺ/** List architecture constraints for a project */
170Ôćĺexport async function listProjectConstraints(input: {
171Ôćĺ  surreal: Surreal;
172Ôćĺ  workspaceRecord: RecordId<"workspace", string>;
173Ôćĺ  projectRecord: RecordId<"project", string>;
174Ôćĺ  area?: string;
175Ôćĺ}): Promise<Array<{ text: string; source: string; severity: "hard" | "soft" }>> {
176Ôćĺ  // Constraints come from two sources:
177Ôćĺ  // 1. Decisions marked as confirmed/contested (hard constraints)
178Ôćĺ  // 2. Observations with severity "conflict" or "warning"
179Ôćĺ
180Ôćĺ  const areaFilter = input.area ? `AND category = $area` : "";
181Ôćĺ
182Ôćĺ  const query = `
183Ôćĺ    LET $project_entity_ids = SELECT VALUE \`in\` FROM belongs_to WHERE out = $project;
184Ôćĺ
185Ôćĺ    SELECT summary AS text, "decision" AS source_type, status, id
186Ôćĺ    FROM decision
187Ôćĺ    WHERE workspace = $workspace
188Ôćĺ      AND id IN $project_entity_ids
189Ôćĺ      AND status IN ["confirmed", "contested"]
190Ôćĺ      ${areaFilter}
191Ôćĺ    ORDER BY created_at DESC LIMIT 30;
192Ôćĺ
193Ôćĺ    SELECT text, "observation" AS source_type, severity, id
194Ôćĺ    FROM observation
195Ôćĺ    WHERE workspace = $workspace
196Ôćĺ      AND status IN ["open", "acknowledged"]
197Ôćĺ      AND severity IN ["conflict", "warning"]
198Ôćĺ    ORDER BY created_at DESC LIMIT 20;
199Ôćĺ  `;
200Ôćĺ
201Ôćĺ  const results = await input.surreal
202Ôćĺ    .query<[null, Array<{ text: string; source_type: string; status: string; id: RecordId }>, Array<{ text: string; source_type: string; severity: string; id: RecordId }>]>(
203Ôćĺ      query,
204Ôćĺ      {
205Ôćĺ        workspace: input.workspaceRecord,
206Ôćĺ        project: input.projectRecord,
207Ôćĺ        ...(input.area ? { area: input.area } : {}),
208Ôćĺ      },
209Ôćĺ    )
210Ôćĺ    .collect<[null, Array<{ text: string; source_type: string; status: string; id: RecordId }>, Array<{ text: string; source_type: string; severity: string; id: RecordId }>]>();
211Ôćĺ
212Ôćĺ  const [, decisionRows, observationRows] = results;
213Ôćĺ
214Ôćĺ  const constraints: Array<{ text: string; source: string; severity: "hard" | "soft" }> = [];
215Ôćĺ
216Ôćĺ  for (const d of decisionRows) {
217Ôćĺ    constraints.push({
