219Ôćĺ      source: `decision:${(d.id as RecordId<string, string>).id as string}`,
220Ôćĺ      severity: d.status === "contested" ? "hard" : "hard",
221Ôćĺ    });
222Ôćĺ  }
223Ôćĺ
224Ôćĺ  for (const o of observationRows) {
225Ôćĺ    constraints.push({
226Ôćĺ      text: o.text,
227Ôćĺ      source: `observation:${(o.id as RecordId<string, string>).id as string}`,
228Ôćĺ      severity: o.severity === "conflict" ? "hard" : "soft",
229Ôćĺ    });
230Ôćĺ  }
231Ôćĺ
232Ôćĺ  return constraints;
233Ôćĺ}
