364Ôćĺ/** Update task status with subtask rollup */
365Ôćĺexport async function updateTaskStatus(input: {
366Ôćĺ  surreal: Surreal;
367Ôćĺ  taskRecord: RecordId<"task", string>;
368Ôćĺ  status: string;
369Ôćĺ  notes?: string;
370Ôćĺ}): Promise<{ task_id: string; status: string; parent_status?: string }> {
371Ôćĺ  const now = new Date();
372Ôćĺ
373Ôćĺ  await input.surreal.update(input.taskRecord).merge({
374Ôćĺ    status: input.status,
375Ôćĺ    updated_at: now,
376Ôćĺ  });
377Ôćĺ
378Ôćĺ  if (input.notes) {
379Ôćĺ    // Append note to description_entries
380Ôćĺ    const task = await input.surreal.select<{ description_entries?: Array<{ text: string; created_at: Date }> }>(input.taskRecord);
381Ôćĺ    const entries = task?.description_entries ?? [];
382Ôćĺ    entries.push({ text: input.notes, created_at: now });
383Ôćĺ    await input.surreal.update(input.taskRecord).merge({ description_entries: entries });
384Ôćĺ  }
385Ôćĺ
386Ôćĺ  // Check if this task has a parent (subtask_of) and compute rollup
387Ôćĺ  const [parentRows] = await input.surreal
388Ôćĺ    .query<[Array<{ out: RecordId<"task", string> }>]>(
389Ôćĺ      "SELECT out FROM subtask_of WHERE `in` = $task LIMIT 1;",
390Ôćĺ      { task: input.taskRecord },
391Ôćĺ    )
392Ôćĺ    .collect<[Array<{ out: RecordId<"task", string> }>]>();
393Ôćĺ
394Ôćĺ  let parentStatus: string | undefined;
395Ôćĺ
396Ôćĺ  if (parentRows.length > 0) {
397Ôćĺ    const parentRecord = parentRows[0].out;
398Ôćĺ    parentStatus = await computeSubtaskRollup(input.surreal, parentRecord);
399Ôćĺ  }
400Ôćĺ
401Ôćĺ  return {
402Ôćĺ    task_id: toId(input.taskRecord),
403Ôćĺ    status: input.status,
404Ôćĺ    ...(parentStatus ? { parent_status: parentStatus } : {}),
405Ôćĺ  };
406Ôćĺ}
