408Ôćĺ/** Compute and apply subtask rollup on a parent task */
409Ôćĺasync function computeSubtaskRollup(
410Ôćĺ  surreal: Surreal,
411Ôćĺ  parentRecord: RecordId<"task", string>,
412Ôćĺ): Promise<string> {
413Ôćĺ  const [subtaskRows] = await surreal
414Ôćĺ    .query<[SubtaskRow[]]>(
415Ôćĺ      `SELECT id, title, status
416Ôćĺ       FROM task
417Ôćĺ       WHERE id IN (SELECT VALUE \`in\` FROM subtask_of WHERE out = $parent);`,
418Ôćĺ      { parent: parentRecord },
419Ôćĺ    )
420Ôćĺ    .collect<[SubtaskRow[]]>();
421Ôćĺ
422Ôćĺ  if (subtaskRows.length === 0) return "unknown";
423Ôćĺ
424Ôćĺ  const allCompleted = subtaskRows.every((s) => s.status === "done" || s.status === "completed");
425Ôćĺ  const anyBlocked = subtaskRows.some((s) => s.status === "blocked");
426Ôćĺ  const anyInProgress = subtaskRows.some((s) => s.status === "in_progress");
427Ôćĺ  const allTodo = subtaskRows.every((s) => s.status === "todo");
428Ôćĺ
429Ôćĺ  let derivedStatus: string;
430Ôćĺ
431Ôćĺ  if (allCompleted) derivedStatus = "completed";
432Ôćĺ  else if (anyBlocked && anyInProgress) derivedStatus = "in_progress";
433Ôćĺ  else if (anyBlocked) derivedStatus = "blocked";
434Ôćĺ  else if (anyInProgress) derivedStatus = "in_progress";
435Ôćĺ  else if (allTodo) derivedStatus = "todo";
436Ôćĺ  else derivedStatus = "in_progress";
437Ôćĺ
438Ôćĺ  await surreal.update(parentRecord).merge({
439Ôćĺ    status: derivedStatus,
440Ôćĺ    updated_at: new Date(),
441Ôćĺ  });
442Ôćĺ
443Ôćĺ  return derivedStatus;
444Ôćĺ}
