528Ôćĺ    summary: input.summary,
529Ôćĺ    ...(input.decisionsMade?.length
530Ôćĺ      ? { decisions_made: input.decisionsMade.map((id) => new RecordId("decision", id)) }
531Ôćĺ      : {}),
532Ôćĺ    ...(input.questionsAsked?.length
533Ôćĺ      ? { questions_asked: input.questionsAsked.map((id) => new RecordId("question", id)) }
534Ôćĺ      : {}),
535Ôćĺ    ...(input.tasksProgressed?.length
536Ôćĺ      ? {
537Ôćĺ          tasks_progressed: input.tasksProgressed.map((t) => ({
538Ôćĺ            task_id: new RecordId("task", t.task_id),
539Ôćĺ            from_status: t.from_status,
540Ôćĺ            to_status: t.to_status,
541Ôćĺ          })),
542Ôćĺ        }
543Ôćĺ      : {}),
544Ôćĺ    ...(input.filesChanged?.length ? { files_changed: input.filesChanged } : {}),
545Ôćĺ    ...(input.observationsLogged?.length
