554Ôćĺ        .relate(sessionRecord, new RecordId("produced", randomUUID()), new RecordId("decision", decisionId), {
555Ôćĺ          added_at: now,
556Ôćĺ        })
557Ôćĺ        .output("after");
558Ôćĺ    }
559Ôćĺ  }
560Ôćĺ
561Ôćĺ  if (input.questionsAsked?.length) {
562Ôćĺ    for (const questionId of input.questionsAsked) {
563Ôćĺ      await input.surreal
564Ôćĺ        .relate(sessionRecord, new RecordId("asked", randomUUID()), new RecordId("question", questionId), {
565Ôćĺ          added_at: now,
566Ôćĺ        })
567Ôćĺ        .output("after");
568Ôćĺ    }
569Ôćĺ  }
570Ôćĺ
571Ôćĺ  if (input.tasksProgressed?.length) {
572Ôćĺ    for (const t of input.tasksProgressed) {
