577Ôćĺ          added_at: now,
578Ôćĺ        })
579Ôćĺ        .output("after");
580Ôćĺ    }
581Ôćĺ  }
582Ôćĺ
583Ôćĺ  return { session_id: toId(sessionRecord), ended: true };
