586Ôćĺ/** Log a git commit to the graph */
587Ôćĺexport async function logCommit(input: {
588Ôćĺ  surreal: Surreal;
589Ôćĺ  workspaceRecord: RecordId<"workspace", string>;
590Ôćĺ  projectRecord: RecordId<"project", string>;
591Ôćĺ  sha: string;
592Ôćĺ  message: string;
593Ôćĺ  filesChanged: Array<{ path: string; change_type: string; lines_added: number; lines_removed: number }>;
594Ôćĺ  author: string;
595Ôćĺ  taskUpdates?: Array<{ task_id: string; new_status: string }>;
596Ôćĺ  decisionsDetected?: Array<{ name: string; rationale: string }>;
597Ôćĺ}): Promise<{ commit_id: string; tasks_updated: number; decisions_created: number }> {
598Ôćĺ  const now = new Date();
599Ôćĺ  const commitRecord = new RecordId("git_commit", randomUUID());
600Ôćĺ
601Ôćĺ  await input.surreal.create(commitRecord).content({
602Ôćĺ    sha: input.sha,
603Ôćĺ    message: input.message,
604Ôćĺ    workspace: input.workspaceRecord,
605Ôćĺ    authored_at: now,
606Ôćĺ    created_at: now,
607Ôćĺ  });
608Ôćĺ
609Ôćĺ  // Update task statuses
610Ôćĺ  let tasksUpdated = 0;
611Ôćĺ  if (input.taskUpdates?.length) {
612Ôćĺ    for (const update of input.taskUpdates) {
613Ôćĺ      const taskRecord = new RecordId("task", update.task_id);
614Ôćĺ      await input.surreal.update(taskRecord).merge({
615Ôćĺ        status: update.new_status,
616Ôćĺ        updated_at: now,
617Ôćĺ      });
618Ôćĺ      tasksUpdated++;
619Ôćĺ    }
620Ôćĺ  }
621Ôćĺ
622Ôćĺ  // Create provisional decisions if flagged
623Ôćĺ  let decisionsCreated = 0;
624Ôćĺ  if (input.decisionsDetected?.length) {
625Ôćĺ    for (const decision of input.decisionsDetected) {
626Ôćĺ      const decisionRecord = new RecordId("decision", randomUUID());
627Ôćĺ      await input.surreal.create(decisionRecord).content({
628Ôćĺ        summary: decision.name,
629Ôćĺ        rationale: decision.rationale,
630Ôćĺ        status: "provisional",
631Ôćĺ        decided_by_name: "code-agent",
632Ôćĺ        workspace: input.workspaceRecord,
633Ôćĺ        source_commit: commitRecord,
634Ôćĺ        created_at: now,
635Ôćĺ        updated_at: now,
636Ôćĺ      });
637Ôćĺ
638Ôćĺ      // Link decision to project
639Ôćĺ      await input.surreal
640Ôćĺ        .relate(decisionRecord, new RecordId("belongs_to", randomUUID()), input.projectRecord, {
641Ôćĺ          added_at: now,
642Ôćĺ        })
643Ôćĺ        .output("after");
644Ôćĺ
645Ôćĺ      // Create implemented_by edge
646Ôćĺ      await input.surreal
647Ôćĺ        .relate(decisionRecord, new RecordId("implemented_by", randomUUID()), commitRecord, {
648Ôćĺ          commit_sha: input.sha,
649Ôćĺ          linked_at: now,
650Ôćĺ        })
651Ôćĺ        .output("after");
652Ôćĺ
653Ôćĺ      decisionsCreated++;
654Ôćĺ    }
655Ôćĺ  }
656Ôćĺ
657Ôćĺ  return {
658Ôćĺ    commit_id: toId(commitRecord),
659Ôćĺ    tasks_updated: tasksUpdated,
660Ôćĺ    decisions_created: decisionsCreated,
661Ôćĺ  };
662Ôćĺ}
