664Ôćĺ// ---------------------------------------------------------------------------
665Ôćĺ// Utility
666Ôćĺ// ---------------------------------------------------------------------------
667Ôćĺ
668Ôćĺfunction levenshteinSimilarity(a: string, b: string): number {
669Ôćĺ  if (a === b) return 1;
670Ôćĺ  const longer = a.length > b.length ? a : b;
671Ôćĺ  const shorter = a.length > b.length ? b : a;
672Ôćĺ  if (longer.length === 0) return 1;
673Ôćĺ
674Ôćĺ  const costs: number[] = [];
675Ôćĺ  for (let i = 0; i <= longer.length; i++) {
676Ôćĺ    let lastValue = i;
677Ôćĺ    for (let j = 0; j <= shorter.length; j++) {
678Ôćĺ      if (i === 0) {
679Ôćĺ        costs[j] = j;
680Ôćĺ      } else if (j > 0) {
681Ôćĺ        let newValue = costs[j - 1];
682Ôćĺ        if (longer.charAt(i - 1) !== shorter.charAt(j - 1)) {
683Ôćĺ          newValue = Math.min(Math.min(newValue, lastValue), costs[j]) + 1;
684Ôćĺ        }
685Ôćĺ        costs[j - 1] = lastValue;
686Ôćĺ        lastValue = newValue;
687Ôćĺ      }
688Ôćĺ    }
689Ôćĺ    if (i > 0) costs[shorter.length] = lastValue;
690Ôćĺ  }
691Ôćĺ
692Ôćĺ  return (longer.length - costs[shorter.length]) / longer.length;
693Ôćĺ}
