11Ôćĺexport function createCreateObservationTool(deps: ChatToolDeps) {
12Ôćĺ  return tool({
13Ôćĺ    description:
14Ôćĺ      "Create an observation in the workspace graph. Use proactively when you notice cross-cutting concerns ÔÇö risks, conflicts, gaps, or notable facts ÔÇö even if the user didn't ask.",
15Ôćĺ    inputSchema: z.object({
16Ôćĺ      text: z.string().min(1).describe("Observation text"),
17Ôćĺ      severity: z
18Ôćĺ        .enum(["info", "warning", "conflict"])
19Ôćĺ        .describe(
20Ôćĺ          "info: awareness-level signals. warning: risks to address soon. conflict: contradictions needing human resolution.",
21Ôćĺ        ),
22Ôćĺ      category: z.enum(ENTITY_CATEGORIES).optional().describe("Optional observation category"),
23Ôćĺ      related_entity_id: z
24Ôćĺ        .string()
25Ôćĺ        .optional()
26Ôćĺ        .describe("Optional related entity id (project/feature/task/decision/question)"),
27Ôćĺ    }),
28Ôćĺ    execute: async (input, options) => {
29Ôćĺ      const context = requireToolContext(options);
30Ôćĺ
31Ôćĺ      const relatedRecord = input.related_entity_id
32Ôćĺ        ? parseRecordIdString(
33Ôćĺ            input.related_entity_id,
34Ôćĺ            ["project", "feature", "task", "decision", "question"],
35Ôćĺ          ) as RecordId<"project" | "feature" | "task" | "decision" | "question", string>
36Ôćĺ        : undefined;
37Ôćĺ
38Ôćĺ      if (relatedRecord) {
39Ôćĺ        const scoped = await isEntityInWorkspace(deps.surreal, context.workspaceRecord, relatedRecord);
40Ôćĺ        if (!scoped) {
41Ôćĺ          throw new Error("related entity is outside the current workspace scope");
42Ôćĺ        }
43Ôćĺ      }
44Ôćĺ
45Ôćĺ      const embedding = await createEmbeddingVector(deps.embeddingModel, input.text, deps.embeddingDimension);
46Ôćĺ      if (!embedding) {
47Ôćĺ        throw new Error("failed to create embedding for create_observation");
48Ôćĺ      }
49Ôćĺ
50Ôćĺ      const observationRecord = await createObservation({
51Ôćĺ        surreal: deps.surreal,
52Ôćĺ        workspaceRecord: context.workspaceRecord,
53Ôćĺ        text: input.text,
54Ôćĺ        severity: input.severity,
55Ôćĺ        ...(input.category ? { category: input.category } : {}),
56Ôćĺ        sourceAgent: context.actor,
57Ôćĺ        now: new Date(),
58Ôćĺ        sourceMessageRecord: context.currentMessageRecord,
59Ôćĺ        ...(relatedRecord ? { relatedRecord } : {}),
60Ôćĺ        embedding,
61Ôćĺ      });
62Ôćĺ
63Ôćĺ      return {
64Ôćĺ        observation_id: `observation:${observationRecord.id as string}`,
65Ôćĺ        severity: input.severity,
66Ôćĺ        status: "open",
67Ôćĺ      };
68Ôćĺ    },
69Ôćĺ  });
70Ôćĺ}
