 52Ôćĺasync function parseJsonBody<T>(request: Request): Promise<T | Response> {
 53Ôćĺ  try {
 54Ôćĺ    return (await request.json()) as T;
 55Ôćĺ  } catch {
 56Ôćĺ    return jsonError("invalid JSON body", 400);
 57Ôćĺ  }
 58Ôćĺ}
