 62Ôćĺfunction normalizeTokens(value: string): Set<string> {
 63Ôćĺ  return new Set(
 64Ôćĺ    value
 65Ôćĺ      .toLowerCase()
 66Ôćĺ      .replace(/[^a-z0-9\s]/g, " ")
 67Ôćĺ      .split(/\s+/)
 68Ôćĺ      .map((t) => t.trim())
 69Ôćĺ      .filter((t) => t.length > 2),
 70Ôćĺ  );
 71Ôćĺ}
 72Ôćĺ
 73Ôćĺfunction hasTokenOverlap(a: Set<string>, b: Set<string>): boolean {
 74Ôćĺ  for (const v of a) {
 75Ôćĺ    if (b.has(v)) return true;
 76Ôćĺ  }
 77Ôćĺ  return false;
 78Ôćĺ}
