281Ôćĺ  /** POST /api/mcp/:workspaceId/decisions/resolve ÔÇö Infer decision from graph */
282Ôćĺ  async function handleResolveDecision(workspaceId: string, request: Request): Promise<Response> {
283Ôćĺ    const auth = await requireAuth(request, workspaceId);
284Ôćĺ    if (auth instanceof Response) return auth;
285Ôćĺ
286Ôćĺ    const body = await parseJsonBody<{
287Ôćĺ      question: string;
288Ôćĺ      options?: string[];
289Ôćĺ      context?: { project?: string; feature?: string };
290Ôćĺ    }>(request);
291Ôćĺ    if (body instanceof Response) return body;
292Ôćĺ    if (!body.question) return jsonError("question is required", 400);
293Ôćĺ
294Ôćĺ    // Embed the question and search for related decisions
295Ôćĺ    const queryEmbedding = await createEmbeddingVector(
296Ôćĺ      deps.embeddingModel,
297Ôćĺ      body.question,
298Ôćĺ      config.embeddingDimension,
299Ôćĺ    );
300Ôćĺ
301Ôćĺ    if (!queryEmbedding) {
302Ôćĺ      return jsonResponse({
303Ôćĺ        decision: undefined,
304Ôćĺ        confidence: 0,
305Ôćĺ        status: "unresolved",
306Ôćĺ        rationale: "Could not create embedding for question",
307Ôćĺ        sources: [],
308Ôćĺ      }, 200);
309Ôćĺ    }
310Ôćĺ
311Ôćĺ    const projectRecord = body.context?.project
312Ôćĺ      ? await resolveWorkspaceProjectRecord({ surreal, workspaceRecord: auth.workspaceRecord, projectInput: body.context.project })
313Ôćĺ      : undefined;
314Ôćĺ
315Ôćĺ    const candidates = await searchEntitiesByEmbedding({
316Ôćĺ      surreal,
317Ôćĺ      workspaceRecord: auth.workspaceRecord,
318Ôćĺ      queryEmbedding,
319Ôćĺ      kinds: ["decision"],
320Ôćĺ      ...(projectRecord ? { projectRecord } : {}),
321Ôćĺ      limit: 10,
322Ôćĺ    });
323Ôćĺ
324Ôćĺ    // Check if any existing decision resolves the question
325Ôćĺ    const questionTokens = normalizeTokens(body.question);
326Ôćĺ    const relevant = candidates.filter((c) => {
327Ôćĺ      const tokens = normalizeTokens(c.name);
328Ôćĺ      return c.score >= 0.78 && hasTokenOverlap(questionTokens, tokens);
329Ôćĺ    });
330Ôćĺ
331Ôćĺ    if (relevant.length > 0) {
332Ôćĺ      const best = relevant[0];
333Ôćĺ      return jsonResponse({
334Ôćĺ        decision: best.name,
335Ôćĺ        confidence: Number(best.score.toFixed(4)),
336Ôćĺ        status: best.status ?? "unknown",
337Ôćĺ        rationale: `Existing ${best.status} decision found with ${(best.score * 100).toFixed(1)}% similarity`,
338Ôćĺ        sources: relevant.map((r) => ({ id: `${r.kind}:${r.id}`, name: r.name, score: Number(r.score.toFixed(4)) })),
339Ôćĺ      }, 200);
340Ôćĺ    }
341Ôćĺ
342Ôćĺ    return jsonResponse({
343Ôćĺ      decision: undefined,
344Ôćĺ      confidence: 0,
345Ôćĺ      status: "unresolved",
346Ôćĺ      rationale: "No existing decision found that resolves this question",
347Ôćĺ      sources: candidates.slice(0, 5).map((c) => ({
348Ôćĺ        id: `${c.kind}:${c.id}`,
349Ôćĺ        name: c.name,
350Ôćĺ        score: Number(c.score.toFixed(4)),
351Ôćĺ      })),
352Ôćĺ    }, 200);
353Ôćĺ  }
