355Ôćĺ  /** POST /api/mcp/:workspaceId/constraints/check ÔÇö Check proposed action */
356Ôćĺ  async function handleCheckConstraints(workspaceId: string, request: Request): Promise<Response> {
357Ôćĺ    const auth = await requireAuth(request, workspaceId);
358Ôćĺ    if (auth instanceof Response) return auth;
359Ôćĺ
360Ôćĺ    const body = await parseJsonBody<{ proposed_action: string; project?: string }>(request);
361Ôćĺ    if (body instanceof Response) return body;
362Ôćĺ    if (!body.proposed_action) return jsonError("proposed_action is required", 400);
363Ôćĺ
364Ôćĺ    const queryEmbedding = await createEmbeddingVector(
365Ôćĺ      deps.embeddingModel,
366Ôćĺ      body.proposed_action,
367Ôćĺ      config.embeddingDimension,
368Ôćĺ    );
369Ôćĺ
370Ôćĺ    if (!queryEmbedding) {
371Ôćĺ      return jsonResponse({ hard_conflicts: [], soft_tensions: [], supporting: [], proceed: true }, 200);
372Ôćĺ    }
373Ôćĺ
374Ôćĺ    const projectRecord = body.project
375Ôćĺ      ? await resolveWorkspaceProjectRecord({ surreal, workspaceRecord: auth.workspaceRecord, projectInput: body.project })
376Ôćĺ      : undefined;
377Ôćĺ
378Ôćĺ    const candidates = await listDecisionConstraintCandidates({
379Ôćĺ      surreal,
380Ôćĺ      workspaceRecord: auth.workspaceRecord,
381Ôćĺ      queryEmbedding,
382Ôćĺ      ...(projectRecord ? { projectRecord } : {}),
383Ôćĺ      limit: 14,
384Ôćĺ    });
385Ôćĺ
386Ôćĺ    const actionTokens = normalizeTokens(body.proposed_action);
387Ôćĺ    const hardConflicts: Array<{ id: string; name: string; score: number; reason: string }> = [];
388Ôćĺ    const softTensions: Array<{ id: string; name: string; score: number; reason: string }> = [];
389Ôćĺ    const supporting: Array<{ id: string; name: string; score: number; reason: string }> = [];
390Ôćĺ
391Ôćĺ    for (const candidate of candidates) {
392Ôćĺ      const candidateTokens = normalizeTokens(candidate.name);
393Ôćĺ      const overlap = hasTokenOverlap(actionTokens, candidateTokens);
394Ôćĺ      const status = candidate.status?.toLowerCase();
395Ôćĺ
396Ôćĺ      if (candidate.kind === "decision" && overlap && (status === "contested" || status === "superseded")) {
397Ôćĺ        hardConflicts.push({
398Ôćĺ          id: `${candidate.kind}:${candidate.id}`,
399Ôćĺ          name: candidate.name,
400Ôćĺ          score: Number(candidate.score.toFixed(4)),
401Ôćĺ          reason: `Decision is marked ${status}.`,
402Ôćĺ        });
403Ôćĺ        continue;
404Ôćĺ      }
405Ôćĺ
406Ôćĺ      if (candidate.kind === "decision" && candidate.score >= 0.86 && overlap) {
407Ôćĺ        supporting.push({
408Ôćĺ          id: `${candidate.kind}:${candidate.id}`,
409Ôćĺ          name: candidate.name,
410Ôćĺ          score: Number(candidate.score.toFixed(4)),
411Ôćĺ          reason: "High-similarity decision aligns with proposed action.",
412Ôćĺ        });
413Ôćĺ        continue;
414Ôćĺ      }
415Ôćĺ
416Ôćĺ      if (candidate.score >= 0.72) {
417Ôćĺ        softTensions.push({
418Ôćĺ          id: `${candidate.kind}:${candidate.id}`,
419Ôćĺ          name: candidate.name,
420Ôćĺ          score: Number(candidate.score.toFixed(4)),
421Ôćĺ          reason: overlap
422Ôćĺ            ? "Related decision/question may require consistency checks."
423Ôćĺ            : "Semantically related context may be affected.",
424Ôćĺ        });
425Ôćĺ      }
426Ôćĺ    }
427Ôćĺ
428Ôćĺ    return jsonResponse({ hard_conflicts: hardConflicts, soft_tensions: softTensions, supporting, proceed: hardConflicts.length === 0 }, 200);
429Ôćĺ  }
