638Ôćĺ    if (body instanceof Response) return body;
639Ôćĺ    if (!body.text) return jsonError("text is required", 400);
640Ôćĺ    if (!body.category) return jsonError("category is required", 400);
641Ôćĺ    if (!body.severity) return jsonError("severity is required", 400);
