680Ôćĺ      sourceAgent: "code-agent",
681Ôćĺ      now,
682Ôćĺ      ...(sourceSessionRecord ? { sourceSessionRecord } : {}),
683Ôćĺ      ...(relatedRecord ? { relatedRecord } : {}),
684Ôćĺ      ...(embedding ? { embedding } : {}),
685Ôćĺ    });
686Ôćĺ
687Ôćĺ    // Create observed_in edge: observation -> agent_session
688Ôćĺ    if (sourceSessionRecord) {
689Ôćĺ      await surreal
690Ôćĺ        .relate(observationRecord, new RecordId("observed_in", crypto.randomUUID()), sourceSessionRecord, {
691Ôćĺ          added_at: now,
692Ôćĺ        })
693Ôćĺ        .output("after");
694Ôćĺ    }
695Ôćĺ
696Ôćĺ    logInfo("mcp.observation.created", "Observation logged via MCP", {
697Ôćĺ      workspaceId,
698Ôćĺ      observationId: observationRecord.id as string,
699Ôćĺ      observationType: body.category,
700Ôćĺ      severity: body.severity,
701Ôćĺ    });
702Ôćĺ
703Ôćĺ    return jsonResponse({
704Ôćĺ      observation_id: `observation:${observationRecord.id as string}`,
705Ôćĺ      severity: body.severity,
706Ôćĺ      status: "open",
