847Ôćĺ    const [decisions, constraints, activeTasks] = await Promise.all([
848Ôćĺ      listProjectDecisions({
849Ôćĺ        surreal,
850Ôćĺ        workspaceRecord: auth.workspaceRecord,
851Ôćĺ        projectRecord,
