854Ôćĺ        surreal,
855Ôćĺ        workspaceRecord: auth.workspaceRecord,
856Ôćĺ        projectRecord,
857Ôćĺ      }),
858Ôćĺ      surreal.query<[Array<{ title: string; status: string }>]>(
859Ôćĺ        `SELECT title, status FROM task WHERE workspace = $ws AND status IN ["todo", "in_progress"] ORDER BY created_at DESC LIMIT 30;`,
860Ôćĺ        { ws: auth.workspaceRecord },
861Ôćĺ      ).then((r) => r[0] ?? []),
862Ôćĺ    ]);
