101Ôćĺexport async function listWorkspaceOpenObservations(input: {
102Ôćĺ  surreal: Surreal;
103Ôćĺ  workspaceRecord: RecordId<"workspace", string>;
104Ôćĺ  limit: number;
105Ôćĺ}): Promise<ObservationSummary[]> {
106Ôćĺ  const [rows] = await input.surreal
107Ôćĺ    .query<[
108Ôćĺ      Array<{
109Ôćĺ        id: ObservationRecord;
110Ôćĺ        text: string;
111Ôćĺ        severity: ObservationSeverity;
112Ôćĺ        status: ObservationStatus;
113Ôćĺ        category?: EntityCategory;
114Ôćĺ        source_agent: string;
115Ôćĺ        created_at: string | Date;
116Ôćĺ      }>,
117Ôćĺ    ]>(
118Ôćĺ      [
119Ôćĺ        "SELECT id, text, severity, status, category, source_agent, created_at",
120Ôćĺ        "FROM observation",
121Ôćĺ        "WHERE workspace = $workspace",
122Ôćĺ        "AND status IN ['open', 'acknowledged']",
123Ôćĺ        "ORDER BY created_at DESC",
124Ôćĺ        "LIMIT $limit;",
125Ôćĺ      ].join(" "),
126Ôćĺ      {
127Ôćĺ        workspace: input.workspaceRecord,
128Ôćĺ        limit: input.limit,
129Ôćĺ      },
130Ôćĺ    )
131Ôćĺ    .collect<[
132Ôćĺ      Array<{
133Ôćĺ        id: ObservationRecord;
134Ôćĺ        text: string;
135Ôćĺ        severity: ObservationSeverity;
136Ôćĺ        status: ObservationStatus;
137Ôćĺ        category?: EntityCategory;
138Ôćĺ        source_agent: string;
139Ôćĺ        created_at: string | Date;
140Ôćĺ      }>,
141Ôćĺ    ]>();
142Ôćĺ
143Ôćĺ  return rows
144Ôćĺ    .slice()
145Ôćĺ    .sort((a, b) => {
146Ôćĺ      const severityDelta = SEVERITY_PRIORITY[a.severity] - SEVERITY_PRIORITY[b.severity];
147Ôćĺ      if (severityDelta !== 0) {
148Ôćĺ        return severityDelta;
149Ôćĺ      }
150Ôćĺ
151Ôćĺ      return new Date(b.created_at).getTime() - new Date(a.created_at).getTime();
152Ôćĺ    })
153Ôćĺ    .map((row) => ({
154Ôćĺ      id: row.id.id as string,
155Ôćĺ      text: row.text,
