157Ôćĺ      status: row.status,
158Ôćĺ      ...(row.category ? { category: row.category } : {}),
159Ôćĺ      sourceAgent: row.source_agent,
160Ôćĺ      createdAt: row.created_at instanceof Date ? row.created_at.toISOString() : new Date(row.created_at).toISOString(),
161Ôćĺ    }));
162Ôćĺ}
