  1Ôćĺimport { RecordId, type Surreal } from "surrealdb";
  2Ôćĺimport type {
  3Ôćĺ  ContextPacket,
  4Ôćĺ  DecisionContext,
  5Ôćĺ  TaskContext,
  6Ôćĺ  QuestionContext,
  7Ôćĺ  ObservationContext,
  8Ôćĺ  TaskScopeContext,
  9Ôćĺ  RecentChangeContext,
 10Ôćĺ} from "./types";
 11Ôćĺ
 12Ôćĺtype ProjectRow = {
 13Ôćĺ  id: RecordId<"project", string>;
 14Ôćĺ  name: string;
 15Ôćĺ  status: string;
 16Ôćĺ  description?: string;
 17Ôćĺ};
 18Ôćĺ
 19Ôćĺtype DecisionRow = {
 20Ôćĺ  id: RecordId<"decision", string>;
 21Ôćĺ  summary: string;
 22Ôćĺ  status: string;
 23Ôćĺ  rationale?: string;
 24Ôćĺ  decided_at?: Date | string;
 25Ôćĺ  category?: string;
 26Ôćĺ  priority?: string;
 27Ôćĺ};
 28Ôćĺ
 29Ôćĺtype TaskRow = {
 30Ôćĺ  id: RecordId<"task", string>;
 31Ôćĺ  title: string;
 32Ôćĺ  status: string;
 33Ôćĺ  priority?: string;
 34Ôćĺ  category?: string;
 35Ôćĺ  description?: string;
 36Ôćĺ  source_session?: RecordId<"agent_session", string>;
 37Ôćĺ};
 38Ôćĺ
 39Ôćĺtype QuestionRow = {
 40Ôćĺ  id: RecordId<"question", string>;
 41Ôćĺ  text: string;
 42Ôćĺ  status: string;
 43Ôćĺ  context?: string;
 44Ôćĺ  priority?: string;
 45Ôćĺ};
 46Ôćĺ
 47Ôćĺtype ObservationRow = {
 48Ôćĺ  id: RecordId<"observation", string>;
 49Ôćĺ  text: string;
 50Ôćĺ  severity: string;
 51Ôćĺ  status: string;
 52Ôćĺ  category?: string;
 53Ôćĺ  observation_type?: string;
 54Ôćĺ};
 55Ôćĺ
 56Ôćĺtype AgentSessionRow = {
 57Ôćĺ  id: RecordId<"agent_session", string>;
 58Ôćĺ  agent: string;
 59Ôćĺ  ended_at?: Date | string;
 60Ôćĺ  summary?: string;
 61Ôćĺ};
 62Ôćĺ
 63Ôćĺtype SubtaskRow = {
 64Ôćĺ  id: RecordId<"task", string>;
 65Ôćĺ  title: string;
 66Ôćĺ  status: string;
 67Ôćĺ};
 68Ôćĺ
 69Ôćĺtype FeatureRow = {
 70Ôćĺ  id: RecordId<"feature", string>;
 71Ôćĺ  name: string;
 72Ôćĺ  description?: string;
 73Ôćĺ};
 74Ôćĺ
 75Ôćĺtype DependencyRow = {
 76Ôćĺ  id: RecordId<"task", string>;
 77Ôćĺ  title: string;
 78Ôćĺ  status: string;
 79Ôćĺ};
 80Ôćĺ
 81Ôćĺfunction toId(record: RecordId<string, string>): string {
 82Ôćĺ  return `${record.table.name}:${record.id as string}`;
 83Ôćĺ}
 84Ôćĺ
 85Ôćĺfunction toIso(value: Date | string | undefined): string {
 86Ôćĺ  if (!value) return "";
 87Ôćĺ  return value instanceof Date ? value.toISOString() : new Date(value).toISOString();
 88Ôćĺ}
 89Ôćĺ
 90Ôćĺ/** Build a broad project context packet (all decisions, tasks, questions for a project) */
 91Ôćĺexport async function buildProjectContext(input: {
 92Ôćĺ  surreal: Surreal;
 93Ôćĺ  workspaceRecord: RecordId<"workspace", string>;
 94Ôćĺ  workspaceName: string;
 95Ôćĺ  projectRecord: RecordId<"project", string>;
 96Ôćĺ  taskId?: string;
 97Ôćĺ  since?: string;
 98Ôćĺ}): Promise<ContextPacket> {
 99Ôćĺ  const { surreal, workspaceRecord, workspaceName, projectRecord, taskId } = input;
100Ôćĺ
101Ôćĺ  // Load project details
102Ôćĺ  const project = await surreal.select<ProjectRow>(projectRecord);
103Ôćĺ  if (!project) {
104Ôćĺ    throw new Error(`project not found: ${projectRecord.id}`);
105Ôćĺ  }
106Ôćĺ
107Ôćĺ  // Load project-scoped entities in parallel
108Ôćĺ  const projectEntitiesQuery = `
109Ôćĺ    LET $project_entity_ids = SELECT VALUE \`in\` FROM belongs_to WHERE out = $project;
110Ôćĺ
111Ôćĺ    SELECT id, summary, status, rationale, decided_at, category, priority
112Ôćĺ    FROM decision
113Ôćĺ    WHERE workspace = $workspace AND id IN $project_entity_ids
114Ôćĺ    ORDER BY created_at DESC LIMIT 50;
115Ôćĺ
116Ôćĺ    SELECT id, title, status, priority, category, description, source_session
117Ôćĺ    FROM task
118Ôćĺ    WHERE workspace = $workspace AND id IN $project_entity_ids
119Ôćĺ    ORDER BY created_at DESC LIMIT 50;
120Ôćĺ
121Ôćĺ    SELECT id, text, status, context, priority
122Ôćĺ    FROM question
123Ôćĺ    WHERE workspace = $workspace AND id IN $project_entity_ids
124Ôćĺ    ORDER BY created_at DESC LIMIT 30;
125Ôćĺ
126Ôćĺ    SELECT id, text, severity, status, category, observation_type
127Ôćĺ    FROM observation
128Ôćĺ    WHERE workspace = $workspace AND status IN ["open", "acknowledged"]
129Ôćĺ    ORDER BY created_at DESC LIMIT 20;
130Ôćĺ  `;
131Ôćĺ
132Ôćĺ  const results = await surreal
133Ôćĺ    .query<[null, DecisionRow[], TaskRow[], QuestionRow[], ObservationRow[]]>(projectEntitiesQuery, {
134Ôćĺ      project: projectRecord,
135Ôćĺ      workspace: workspaceRecord,
136Ôćĺ    })
137Ôćĺ    .collect<[null, DecisionRow[], TaskRow[], QuestionRow[], ObservationRow[]]>();
138Ôćĺ
139Ôćĺ  const [, decisionRows, taskRows, questionRows, observationRows] = results;
140Ôćĺ
141Ôćĺ  // Categorize decisions by status
142Ôćĺ  const confirmed: DecisionContext[] = [];
143Ôćĺ  const provisional: DecisionContext[] = [];
144Ôćĺ  const contested: DecisionContext[] = [];
145Ôćĺ
146Ôćĺ  for (const d of decisionRows) {
147Ôćĺ    const ctx: DecisionContext = {
148Ôćĺ      id: toId(d.id),
149Ôćĺ      summary: d.summary,
150Ôćĺ      status: d.status,
151Ôćĺ      ...(d.rationale ? { rationale: d.rationale } : {}),
152Ôćĺ      ...(d.decided_at ? { decided_at: toIso(d.decided_at) } : {}),
153Ôćĺ      ...(d.category ? { category: d.category } : {}),
154Ôćĺ      ...(d.priority ? { priority: d.priority } : {}),
155Ôćĺ    };
156Ôćĺ
157Ôćĺ    if (d.status === "contested") {
158Ôćĺ      contested.push(ctx);
159Ôćĺ    } else if (d.status === "provisional" || d.status === "inferred") {
160Ôćĺ      provisional.push(ctx);
161Ôćĺ    } else if (d.status === "confirmed") {
162Ôćĺ      confirmed.push(ctx);
163Ôćĺ    }
164Ôćĺ  }
165Ôćĺ
166Ôćĺ  // Map tasks
167Ôćĺ  const activeTasks: TaskContext[] = taskRows
168Ôćĺ    .filter((t) => t.status !== "done" && t.status !== "completed")
169Ôćĺ    .map((t) => ({
170Ôćĺ      id: toId(t.id),
171Ôćĺ      title: t.title,
172Ôćĺ      status: t.status,
173Ôćĺ      ...(t.priority ? { priority: t.priority } : {}),
174Ôćĺ      ...(t.category ? { category: t.category } : {}),
175Ôćĺ      ...(t.source_session ? { source_session: toId(t.source_session) } : {}),
176Ôćĺ    }));
177Ôćĺ
178Ôćĺ  // Map questions
179Ôćĺ  const openQuestions: QuestionContext[] = questionRows
180Ôćĺ    .filter((q) => q.status !== "answered" && q.status !== "resolved")
181Ôćĺ    .map((q) => ({
182Ôćĺ      id: toId(q.id),
183Ôćĺ      text: q.text,
184Ôćĺ      status: q.status,
185Ôćĺ      ...(q.context ? { context: q.context } : {}),
186Ôćĺ      ...(q.priority ? { priority: q.priority } : {}),
187Ôćĺ    }));
188Ôćĺ
189Ôćĺ  // Map observations
190Ôćĺ  const observations: ObservationContext[] = observationRows.map((o) => ({
191Ôćĺ    id: toId(o.id),
192Ôćĺ    text: o.text,
193Ôćĺ    severity: o.severity,
194Ôćĺ    status: o.status,
195Ôćĺ    ...(o.category ? { category: o.category } : {}),
196Ôćĺ    ...(o.observation_type ? { observation_type: o.observation_type } : {}),
197Ôćĺ  }));
198Ôćĺ
199Ôćĺ  // Build recent changes if `since` provided
200Ôćĺ  const recentChanges: RecentChangeContext[] = input.since
201Ôćĺ    ? await loadRecentChanges(surreal, workspaceRecord, projectRecord, input.since)
202Ôćĺ    : [];
203Ôćĺ
204Ôćĺ  // Build task scope if taskId provided
205Ôćĺ  let taskScope: TaskScopeContext | undefined;
206Ôćĺ  if (taskId) {
207Ôćĺ    taskScope = await buildTaskScope(surreal, workspaceRecord, projectRecord, taskId);
208Ôćĺ  }
209Ôćĺ
210Ôćĺ  return {
211Ôćĺ    workspace: { id: workspaceRecord.id as string, name: workspaceName },
212Ôćĺ    project: {
213Ôćĺ      id: projectRecord.id as string,
214Ôćĺ      name: project.name,
215Ôćĺ      status: project.status,
216Ôćĺ      ...(project.description ? { description: project.description } : {}),
217Ôćĺ    },
218Ôćĺ    ...(taskScope ? { task_scope: taskScope } : {}),
219Ôćĺ    decisions: { confirmed, provisional, contested },
220Ôćĺ    active_tasks: activeTasks,
221Ôćĺ    open_questions: openQuestions,
222Ôćĺ    recent_changes: recentChanges,
223Ôćĺ    observations,
224Ôćĺ  };
225Ôćĺ}
226Ôćĺ
